const now = new Date();
const yearMonth = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
const monthName = now.toLocaleString('default', { month: 'long' });

// Get previous month's attendance for LOP calculation
// For simplicity, assume full month unless specified

const employees = $input.all()[0].json;
const payrollRecords = [];

for (const emp of employees) {
  const ctc = parseFloat(emp.ctc_annual || 0);
  const basic = Math.round(ctc * 0.4 / 12);
  const hra = Math.round(ctc * 0.2 / 12);
  const conveyance = Math.round(ctc * 0.05 / 12);
  const medical = Math.round(ctc * 0.05 / 12);
  const special = Math.round(ctc * 0.3 / 12);

  const gross = basic + hra + conveyance + medical + special;

  // Deductions (based on Indian norms)
  const pfEmployee = Math.min(Math.round(basic * 0.12), 1800); // Max 1800
  const pfEmployer = pfEmployee;
  const esiEmployee = gross <= 21000 ? Math.round(gross * 0.0075) : 0;
  const esiEmployer = gross <= 21000 ? Math.round(gross * 0.0325) : 0;

  // Professional tax (Gujarat rates)
  let profTax = 0;
  if (gross > 12000) profTax = 200;

  // TDS placeholder - calculate based on taxable income
  const tds = 0; // To be calculated based on projection

  const totalDeductions = pfEmployee + esiEmployee + tds + profTax;
  const netSalary = gross - totalDeductions;

  payrollRecords.push({
    employee_id: emp.employee_id,
    year_month: yearMonth,
    month_name: monthName,
    basic_salary: basic,
    hra: hra,
    conveyance_allowance: conveyance,
    medical_allowance: medical,
    special_allowance: special,
    gross_earnings: gross,
    pf_employee: pfEmployee,
    pf_employer: pfEmployer,
    esi_employee: esiEmployee,
    esi_employer: esiEmployer,
    tds: tds,
    professional_tax: profTax,
    total_deductions: totalDeductions,
    net_salary: netSalary,
    payment_status: 'Pending'
  });
}

return payrollRecords.map(r => ({ json: r }));

